// Generated by AI (UnitTest MCP)
//! Deterministic comparison of independent same-file tasks and progressive handoff.

use std::path::{Path, PathBuf};
use std::time::{SystemTime, UNIX_EPOCH};

use lodestar_core::{
    now_unix, CodeBindingMode, ConformanceEvidence, EvidenceProvenance, GoalKind, Lodestar, Result,
    Task, TaskStatus,
};
use serde_json::json;

const ARTIFACT: &str = "artifact:src/lib.rs";
const LEASE_SECS: i64 = 300;

fn main() -> Result<()> {
    let root = temporary_root();
    std::fs::create_dir_all(&root)?;
    let evaluated = evaluate(&root);
    let cleanup = std::fs::remove_dir_all(&root);
    match (evaluated, cleanup) {
        (Ok(result), Ok(())) => {
            println!("{}", serde_json::to_string_pretty(&result)?);
            Ok(())
        }
        (Err(error), _) => Err(error),
        (Ok(_), Err(error)) => Err(error.into()),
    }
}

fn evaluate(root: &Path) -> Result<serde_json::Value> {
    let independent_path = root.join("independent.db");
    let handoff_path = root.join("handoff.db");

    let independent = independent_arm(&independent_path)?;
    let progressive = progressive_arm(&handoff_path)?;
    Ok(json!({
        "schema_version": 1,
        "scenario": "same_file_progressive_handoff",
        "artifact": ARTIFACT,
        "independent_tasks": independent,
        "progressive_handoff": progressive,
        "decision": {
            "advisory_symbol_leases_required": false,
            "reason": "Explicit task dependencies serialize same-file ownership; measure agent adherence before adding advisory resource leases."
        }
    }))
}

fn independent_arm(path: &Path) -> Result<serde_json::Value> {
    let setup = Lodestar::open(path.to_str().unwrap())?;
    let goal = setup.define_goal(
        GoalKind::Objective,
        "Edit two symbols",
        "Complete both same-file edits",
        None,
    )?;
    setup.link_goal_to_code(&goal.id, &[ARTIFACT.to_string()], CodeBindingMode::Governed)?;
    let bound_to_shared_artifact = setup
        .store()
        .code_for_goal(&goal.id)?
        .contains(&ARTIFACT.to_string());
    let first = setup.create_task(&goal.id, "Edit Router", "Router complete")?;
    let second = setup.create_task(&goal.id, "Edit helper", "helper complete")?;
    drop(setup);

    let agent_a = Lodestar::open(path.to_str().unwrap())?;
    let agent_b = Lodestar::open(path.to_str().unwrap())?;
    let first_claimed = agent_a.claim_task(&first.id, "agent-a", LEASE_SECS)?;
    let second_claimed = agent_b.claim_task(&second.id, "agent-b", LEASE_SECS)?;
    let concurrent_claims = agent_a
        .board(true)?
        .iter()
        .filter(|task| task.status == TaskStatus::Claimed)
        .count();

    Ok(json!({
        "first_claimed": first_claimed,
        "second_claimed": second_claimed,
        "same_artifact": bound_to_shared_artifact,
        "concurrent_claims": concurrent_claims,
        "concurrent_same_file_ownership_risk": bound_to_shared_artifact && first_claimed && second_claimed && concurrent_claims == 2
    }))
}

fn progressive_arm(path: &Path) -> Result<serde_json::Value> {
    let setup = Lodestar::open(path.to_str().unwrap())?;
    let goal = setup.define_goal(
        GoalKind::Objective,
        "Edit two symbols safely",
        "Serialize same-file edits through task handoff",
        None,
    )?;
    setup.link_goal_to_code(&goal.id, &[ARTIFACT.to_string()], CodeBindingMode::Governed)?;
    let first = setup.create_task(&goal.id, "Edit Router", "Router complete")?;
    let second = setup.create_task_after(
        &goal.id,
        "Edit helper",
        "helper complete",
        Some(first.id.clone()),
    )?;
    drop(setup);

    let agent_a = Lodestar::open(path.to_str().unwrap())?;
    let agent_b = Lodestar::open(path.to_str().unwrap())?;
    let first_claimed = agent_a.claim_task(&first.id, "agent-a", LEASE_SECS)?;
    let early_second_claim = agent_b.claim_task(&second.id, "agent-b", LEASE_SECS)?;
    let concurrent_before = claimed_count(&agent_a)?;
    let claimed_first = agent_a.store().get_task(&first.id)?.unwrap();
    let evidence = aligned_evidence(&claimed_first, "agent-a");
    let check = agent_a.check_conformance(&evidence, Some(&first.id))?;
    let (first_completed, conformance) =
        agent_a.complete_task(&first.id, "agent-a", &evidence, &check)?;
    let successor_after_completion = agent_b.store().get_task(&second.id)?.unwrap();
    let second_claimed_after_handoff = agent_b.claim_task(&second.id, "agent-b", LEASE_SECS)?;
    let concurrent_after = claimed_count(&agent_b)?;

    Ok(json!({
        "first_claimed": first_claimed,
        "early_second_claim": early_second_claim,
        "concurrent_claims_before_handoff": concurrent_before,
        "first_completed": first_completed,
        "completion_verdict": conformance.verdict.as_str(),
        "successor_status_after_completion": successor_after_completion.status.as_str(),
        "successor_dependency_cleared": successor_after_completion.blocked_by.is_none(),
        "second_claimed_after_handoff": second_claimed_after_handoff,
        "concurrent_claims_after_handoff": concurrent_after,
        "max_concurrent_claims": concurrent_before.max(concurrent_after),
        "concurrent_same_file_ownership_risk": concurrent_before > 1 || concurrent_after > 1,
        "synthetic_conformance_evidence": true
    }))
}

fn aligned_evidence(task: &Task, agent: &str) -> ConformanceEvidence {
    let execution_id = format!("execution:{}", task.id.trim_start_matches("task:"));
    let started_at = task.claim_started_at.unwrap();
    let ended_at = now_unix();
    ConformanceEvidence {
        schema_version: 1,
        task_id: Some(task.id.clone()),
        agent_id: agent.to_string(),
        started_at,
        ended_at,
        changed_node_ids: vec![ARTIFACT.to_string()],
        failed_node_ids: vec![],
        execution_ids: vec![execution_id.clone()],
        successful_execution_ids: vec![execution_id.clone()],
        commit_ids: vec![],
        summary: "completed the governed same-file subtask".to_string(),
        provenance: vec![
            EvidenceProvenance {
                source_id: format!("agent:{agent}"),
                target_id: execution_id.clone(),
                relation: "observed".to_string(),
            },
            EvidenceProvenance {
                source_id: execution_id,
                target_id: ARTIFACT.to_string(),
                relation: "modified".to_string(),
            },
        ],
    }
}

fn claimed_count(engine: &Lodestar) -> Result<usize> {
    Ok(engine
        .board(true)?
        .iter()
        .filter(|task| task.status == TaskStatus::Claimed)
        .count())
}

fn temporary_root() -> PathBuf {
    let nanos = SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .map(|duration| duration.as_nanos())
        .unwrap_or_default();
    std::env::temp_dir().join(format!(
        "mindleak-handoff-evaluation-{}-{}",
        std::process::id(),
        nanos
    ))
}
